package com.chaobo.scm.supplier.infrastructure.persistence.qualification;
import org.apache.ibatis.annotations.*;import java.util.*;
@Mapper public interface QualificationRequirementMapper {record Row(long id,String supplierType,Long categoryId,String qualificationType,boolean mandatory,int status,int version){}@Select("SELECT requirement_id id,supplier_type supplierType,category_id categoryId,qualification_type qualificationType,mandatory,status,version FROM sup_qualification_requirement WHERE requirement_id=#{id}")Row find(long id);@Insert("INSERT INTO sup_qualification_requirement(requirement_id,supplier_type,category_id,qualification_type,mandatory,status,created_by,updated_by,version) VALUES(#{r.id},#{r.supplierType},#{r.categoryId},#{r.qualificationType},#{r.mandatory},#{r.status},#{operator},#{operator},0)")void insert(@Param("r")Row row,@Param("operator")long operator);@Update("UPDATE sup_qualification_requirement SET supplier_type=#{r.supplierType},category_id=#{r.categoryId},qualification_type=#{r.qualificationType},mandatory=#{r.mandatory},status=#{r.status},updated_by=#{operator},version=version+1 WHERE requirement_id=#{r.id} AND version=#{version}")int update(@Param("r")Row row,@Param("version")int version,@Param("operator")long operator);@Select("SELECT requirement_id id,supplier_type supplierType,category_id categoryId,qualification_type qualificationType,mandatory,status,version FROM sup_qualification_requirement ORDER BY updated_at DESC")List<Row> list();}
